mapper.select:
select self_process_no,self_process_group,self_process_type,clos_type,feedback_msg,occur_time,feedback_time,ticket_id,ticket_type,alarmno,clos_status,clos_time
from nia.tb_auto_treat_process_dtl pd
where pd.ticket_id = #{num} or pd.alarmno = #{num}
limit 1;

SELECT self_process_no,self_process_group,self_process_type,clos_type,feedback_msg,occur_time,feedback_time,ticket_id,ticket_type,alarmno,clos_status,clos_time
FROM nia.tb_auto_treat_process_dtl t
where t.ticket_id = #{ticketId}

select tlc.root_cause_sysnamea ,tlc.root_cause_porta from rca.tb_rca_ticket_al_current tlc
inner join rca.tb_rca_ticket_current tc on tlc.ticket_id = tc.ticket_id
where tc.ticket_id = #{ticketId}

mapper.update:
UPDATE rca.tb_syslog_alarm_mst
SET status = 'FIN'
WHERE alarmno = #{alarmno}

update nia.tb_auto_treat_process_dtl
set self_process_type = 'F' , self_process_group = 'ST', ticket_type = 'FTT'
where ticket_id = #{ticketId}

update nia.tb_sop
set zero1_model = #{model}::int , zero1_entropy = #{entropy}::double precision
where ticket_id = #{ticketId}
